set -e
mkdir -p /scripts /data
cat > /data/input.csv <<'CSV'
id,name,age
1,Alice,30
2,Bob,25
3,Charlie,40
CSV
cat > /scripts/report.sh <<'SH'
#!/usr/bin/env bash

usage() {
  cat <<'USAGE'
Usage: report.sh [-f format] [-o file] [-v] [-h]
  -f <format>  Output format: csv or json (default: csv)
  -o <file>    Output file (default: stdout)
  -v           Verbose mode
  -h           Show this help and exit
USAGE
}

format="csv"
outfile=""
verbose=0

while getopts ":f:o:vh" opt; do
  case "$opt" in
    f) format="$OPTARG";;
    o) outfile="$OPTARG";;
    v) verbose=1;;
    h) usage; exit 0;;
    \?) echo "Error: invalid option -$OPTARG" >&2; usage >&2; exit 2;;
    :)  echo "Error: option -$OPTARG requires an argument" >&2; usage >&2; exit 2;;
  esac
done
shift $((OPTIND-1))

if [[ "$format" != "csv" && "$format" != "json" ]]; then
  echo "Error: unsupported format '$format' (use csv or json)" >&2
  exit 2
fi

input="/data/input.csv"
if [[ ! -f "$input" ]]; then
  echo "Error: input file not found: $input" >&2
  exit 1
fi

# Count data rows (excluding header)
rows=$(awk 'NR>1{c++} END{print c+0}' "$input")

emit() {
  if [[ -n "$outfile" ]]; then
    cat > "$outfile"
  else
    cat
  fi
}

{
  if [[ $verbose -eq 1 ]]; then
    echo "Verbose: processing $rows rows"
  fi

  if [[ "$format" == "csv" ]]; then
    cat "$input"
  else
    # Convert CSV to JSON array of objects.
    awk -F',' '
      function esc(s,   t) {
        gsub(/\\/, "\\\\", s)
        gsub(/\"/, "\\\"", s)
        gsub(/\r/, "", s)
        gsub(/\n/, "\\n", s)
        return s
      }
      NR==1 { for (i=1;i<=NF;i++) h[i]=$i; next }
      NR==2 { print "["; first=1 }
      {
        if (!first) print ",";
        first=0
        printf "  {";
        for (i=1;i<=NF;i++) {
          key=esc(h[i]); val=esc($i);
          printf "%s\"%s\":\"%s\"", (i>1?",":""), key, val;
        }
        printf "}";
      }
      END { if (NR>1) print "\n]"; else print "[]" }
    ' "$input"
  fi
} | emit
SH
chmod +x /scripts/report.sh

# Run as requested
bash /scripts/report.sh -f json -v

