#!/bin/bash

factorial() {
  local n=$1
  if [ $n -le 1 ]; then
    echo 1
  else
    local sub=$(factorial $((n-1)))
    echo $((n * sub))
  fi
}

result=$(factorial 5
echo "factorial(5) = $result"
exit 0

