awk '
function trim(s){gsub(/^[ \t]+|[ \t]+$/,"",s); return s}

# First pass: defaults
FNR==NR{
  line=$0
  if(line ~ /^[ \t]*\[/){
    section=line
    if(!(section in sec_seen_def)){
      sec_seen_def[section]=1
      sec_order[++sec_n]=section
    }
    next
  }
  if(line ~ /^[ \t]*$/ || line ~ /^[ \t]*[;#]/){ next }
  split(line,a,"="); key=trim(a[1])
  def[section SUBSEP key]=line
  def_keys[section SUBSEP key]=1
  if(!( (section SUBSEP key) in key_order_def_seen)){
    key_order_def_seen[section SUBSEP key]=1
    key_order_def[++key_n_def]=section SUBSEP key
  }
  next
}

# Second pass: custom
{
  line=$0
  if(line ~ /^[ \t]*\[/){
    section=line
    if(!(section in sec_seen_all)){
      sec_seen_all[section]=1
      if(!(section in sec_seen_def)){
        sec_order[++sec_n]=section
      }
    }
    next
  }
  if(line ~ /^[ \t]*$/ || line ~ /^[ \t]*[;#]/){ next }
  split(line,a,"="); key=trim(a[1])
  cus[section SUBSEP key]=line
  cus_keys[section SUBSEP key]=1
  if(!( (section SUBSEP key) in key_order_cus_seen)){
    key_order_cus_seen[section SUBSEP key]=1
    key_order_cus[++key_n_cus]=section SUBSEP key
  }
}

END{
  for(si=1; si<=sec_n; si++){
    sec=sec_order[si]
    if(sec=="") continue
    print sec

    # print keys from defaults in their appearance order
    for(ki=1; ki<=key_n_def; ki++){
      split(key_order_def[ki], t, SUBSEP)
      if(t[1]!=sec) continue
      k = t[2]
      idx = sec SUBSEP k
      if(idx in cus_keys) print cus[idx]; else if(idx in def_keys) print def[idx]
    }

    # print keys that exist only in custom (not in defaults), in custom appearance order
    for(ki=1; ki<=key_n_cus; ki++){
      split(key_order_cus[ki], t, SUBSEP)
      if(t[1]!=sec) continue
      k=t[2]
      idx=sec SUBSEP k
      if(!(idx in def_keys) && (idx in cus_keys)) print cus[idx]
    }

    if(si<sec_n) print ""
  }
}
' /config/defaults.ini /config/custom.ini | tee /config/merged.ini

